def reset_joints_random_or_default(
    env: ManagerBasedRlEnv,
    env_ids: torch.Tensor | None,
    preset_probability: float = 0.9,
    default_position_range: tuple[float, float] = (-0.1, 0.1),
    default_velocity_range: tuple[float, float] = (-0.05, 0.05),
    asset_cfg: SceneEntityCfg = _DEFAULT_ASSET_CFG,
) -> None:
    """Reset root and joints using random preset configurations or around default values.
    
    With probability `preset_probability` (default 0.9), randomly selects one of the
    preset qpos configurations (which includes root pose + joint positions). 
    Otherwise, initializes around the default root and joint states with small random offsets.
    
    Note: Preset qpos format is [root_pos (3), root_quat (4), joint_pos (26)], total 33 values.
    
    Args:
        env: The environment.
        env_ids: Environment IDs to reset. If None, resets all environments.
        preset_probability: Probability of using a preset configuration (default: 0.9).
        default_position_range: Position offset range when using default mode.
        default_velocity_range: Velocity range when using default mode.
        asset_cfg: Asset configuration.
    """
    if env_ids is None:
        env_ids = torch.arange(env.num_envs, device=env.device, dtype=torch.int)
    
    asset: Entity = env.scene[asset_cfg.name]
    
    # Get default states
    default_root_state = asset.data.default_root_state
    assert default_root_state is not None
    default_joint_pos = asset.data.default_joint_pos
    assert default_joint_pos is not None
    default_joint_vel = asset.data.default_joint_vel
    assert default_joint_vel is not None
    soft_joint_pos_limits = asset.data.soft_joint_pos_limits
    assert soft_joint_pos_limits is not None
    
    num_envs = len(env_ids)
    num_joints = default_joint_pos.shape[1]
    
    # Convert preset qpos to tensor (only once)
    # Format: [root_pos (3), root_quat (4), joint_pos (26)] = 33 values
    if not hasattr(reset_joints_random_or_default, '_preset_qpos_tensor'):
        reset_joints_random_or_default._preset_qpos_tensor = torch.tensor(
            _PRESET_QPOS, device=env.device, dtype=torch.float32
        )
    preset_tensor = reset_joints_random_or_default._preset_qpos_tensor
    
    # Randomly decide which environments use preset vs default
    use_preset = torch.rand(num_envs, device=env.device) < preset_probability
    
    # Initialize root states (13 values: pos, quat, lin_vel, ang_vel)
    root_states = default_root_state[env_ids].clone()
    
    # Initialize joint positions and velocities
    joint_pos = torch.zeros((num_envs, num_joints), device=env.device)
    joint_vel = torch.zeros((num_envs, num_joints), device=env.device)
    
    # Handle environments using preset configurations
    if use_preset.any():
        num_preset_envs = use_preset.sum().item()
        # Randomly select preset indices for each environment
        preset_indices = torch.randint(
            0, len(_PRESET_QPOS), (num_preset_envs,), device=env.device
        )
        selected_presets = preset_tensor[preset_indices]
        
        # Split preset: root pose (0:7) and joint positions (7:33)
        preset_root_pos = selected_presets[:, 0:3]  # xyz position
        preset_root_quat = selected_presets[:, 3:7]  # xyzw quaternion
        preset_joint_pos = selected_presets[:, 7:]  # joint positions
        
        # Set root state (with env_origins offset)
        root_states[use_preset, 0:3] = preset_root_pos + env.scene.env_origins[env_ids[use_preset]]
        root_states[use_preset, 3:7] = preset_root_quat
        root_states[use_preset, 7:13] = 0.0  # Zero velocities
        
        # Set joint positions
        joint_pos[use_preset] = preset_joint_pos
        # Zero velocity for preset configurations
        joint_vel[use_preset] = 0.0
    
    # Handle environments using default with offset
    if (~use_preset).any():
        default_env_mask = ~use_preset
        default_env_ids_local = torch.where(default_env_mask)[0]
        
        # Root state already initialized with defaults above
        # Just add small random offsets to velocities
        vel_offset = sample_uniform(
            default_velocity_range[0],
            default_velocity_range[1],
            (len(default_env_ids_local), 6),
            env.device
        )
        root_states[default_env_mask, 7:13] += vel_offset
        
        # Get default joint positions for these environments
        default_pos = default_joint_pos[env_ids[default_env_ids_local]]
        default_vel = default_joint_vel[env_ids[default_env_ids_local]]
        
        # Add random offsets
        pos_offset = sample_uniform(
            default_position_range[0],
            default_position_range[1],
            (len(default_env_ids_local), num_joints),
            env.device
        )
        vel_offset = sample_uniform(
            default_velocity_range[0],
            default_velocity_range[1],
            (len(default_env_ids_local), num_joints),
            env.device
        )
        
        joint_pos[default_env_mask] = default_pos + pos_offset
        joint_vel[default_env_mask] = default_vel + vel_offset
    
    # Clamp joint positions to limits
    joint_pos_limits = soft_joint_pos_limits[env_ids]
    joint_pos = joint_pos.clamp_(joint_pos_limits[..., 0], joint_pos_limits[..., 1])
    
    # Write root state to simulation (handles both floating-base and mocap)
    if asset.is_fixed_base and asset.is_mocap:
        # Fixed-base mocap entity - write mocap pose only
        mocap_pose = root_states[:, 0:7]  # position + orientation
        asset.write_mocap_pose_to_sim(mocap_pose, env_ids=env_ids)
    elif not asset.is_fixed_base:
        # Floating-base entity - write full root state
        asset.write_root_state_to_sim(root_states, env_ids=env_ids)
    
    # Write joint states to simulation
    asset.write_joint_state_to_sim(joint_pos, joint_vel, env_ids=env_ids)
